int alctoken(int category)
{
    struct tree *t = malloc(sizeof(struct tree));
    if (t == NULL) {
        fprintf(stderr, "Failed to allocate memory for tree node\n");
        exit(1);
    }

    // initialize kids
    for (int i = 0; i < 10; i++) {
        t->kids[i] = NULL;
    }

    t->id = serial++;
    t->prodrule = category;
    t->symbolname = NULL;
    t->nkids = 0;

    t->type = NULL; // not needed for leaf typing
    

    t->leaf = malloc(sizeof(struct token));
    if (t->leaf == NULL) {
        fprintf(stderr, "Failed to allocate memory for token\n");
        exit(1);
    }

    // malloc the type pointer for this token
    t->leaf->type = malloc(sizeof(*(t->leaf->type)));
    memset(t->leaf->type, 0, sizeof(*(t->leaf->type)));

    switch (category)
    {
        case KEYWORD_ERROR:
            fprintf(stderr, "%s:%d: scanner error: Kotlin reserved keyword: \"%s\" is not a part of k0\n",
                   filename, lineno, yytext);
            exit_status = 1;
            break;

        case UNCLOSED_COMMENT:
            fprintf(stderr, "%s:%d: scanner error: unclosed multi-line comment\n",
                   filename, multi_line_start);
            exit_status = 1;
            break;

        case COULD_NOT_MATCH:
            fprintf(stderr, "%s:%d: scanner error: \'%s\' could not be matched\n",
                   filename, lineno, yytext);
            exit_status = 1;
            break;

        case ILL_IDENT:
            fprintf(stderr, "%s:%d: scanner error: \'%s\' is an illegal identifier\n",
                   filename, lineno, yytext);
            exit_status = 1;
            break;

        case OP_ERROR:
            fprintf(stderr, "%s:%d: scanner error: \'%s\' is an illegal operator\n",
                   filename, lineno, yytext);
            exit_status = 1;
            break;

        default:
            break;
    }

    // fill token fields
    t->leaf->category = category;
    t->leaf->text = strdup(yytext);
    t->leaf->lineno = lineno;
    t->leaf->filename = strdup(filename);

    t->leaf->ival = 0;
    t->leaf->dval = 0.0;
    t->leaf->sval = NULL;

    switch (category)
    {
        case INT:
            t->leaf->ival = atoi(yytext);
            t->leaf->type->basetype = INT_TYPE;
            break;

        case REAL:
            t->leaf->dval = atof(yytext);
            t->leaf->type->basetype = DOUBLE_TYPE;
            break;

        case STRING:
        case MULTI_STRING:
            t->leaf->sval = consume_sval(category);
            if (t->leaf->sval == NULL) {
                fprintf(stderr, "%s:%d: scanner error: unsupported escape sequence in %s\n",
                       filename, lineno, yytext);
                exit_status = 1;
            }
            t->leaf->type->basetype = STRING_TYPE;
            break;
        case CHAR:
            t->leaf->type->basetype = CHAR_TYPE;
            break;
        case K_FALSE:
        case K_TRUE:
            t->leaf->type->basetype = BOOLEAN_TYPE;
            break;

    }

    yylval.treeptr = t;
    return category;
}

char *consume_sval(int str_type)
{
    // allocate worst-case size (raw string length including escapes and quotes)
    char *tmp = (char *)malloc(yyleng + 1);
    char *start = tmp;

    // pointer to iterate over the raw lexer text
    char *raw_text = yytext + 1;     // skip initial quote
    char *end = yytext + yyleng - 1; // stop before final quote

    if (str_type == MULTI_STRING)
    {
        raw_text = yytext + 3;
        end = yytext + yyleng - 3;
    }

    // iterate through raw text, consuming escapes and copying characters
    while (raw_text < end)
    {
        // encountered a backslash, meaning an escape sequence
        if (*raw_text == '\\')
        {
            raw_text++; // move to escaped character

            // check what the escaped character is
            switch (*raw_text)
            {
            case 'n': // consume newline
                *tmp = '\n';
                break;
            case 't': // consume tab
                *tmp = '\t';
                break;
            case '\\': // consume literal backslash
                *tmp = '\\';
                break;
            case '\'': // consume apostrophe
                *tmp = '\'';
                break;
            case '\"': // consume quote
                *tmp = '\"';
                break;
            case 'r': // consume carriage return
                *tmp = '\r';
                break;
            case 'b': // consume backspace
                *tmp = '\b';
                break;
            default:
                // unsupported escape sequence
                free(start);
                return NULL;
            }
        }
        else
        {
            // regular character, copy as-is
            *tmp = *raw_text;
        }

        tmp++;
        raw_text++;
    }

    // null-terminate the final string value
    *tmp = '\0';

    return start;
}
